mapper.select:
SELECT "instanceId", "propertyGroupId", "propertyId", "propertyValue", "propertyDesc", "curVersion", "defaultValue", "propertyName", "dataType" FROM ( SELECT wp.INSTANCE_ID AS "instanceId", wp.PROPERTY_GROUP_ID AS "propertyGroupId", wp.PROPERTY_ID AS "propertyId", wp.PROPERTY_VALUE AS "propertyValue", wp.PROPERTY_DESC AS "propertyDesc", wp.CUR_VERSION AS "curVersion", COALESCE(p.DEFAULT_VALUE, 'USE_DEFAULT') AS "defaultValue", p.PROPERTY_NAME AS "propertyName", p.DATA_TYPE AS "dataType", ROW_NUMBER() OVER (ORDER BY ${orderColumn} ${orderDir}) AS RN FROM FWK_WAS_PROPERTY wp LEFT JOIN FWK_PROPERTY p ON wp.PROPERTY_GROUP_ID = p.PROPERTY_GROUP_ID AND wp.PROPERTY_ID = p.PROPERTY_ID WHERE wp.INSTANCE_ID = #{instanceId}
AND wp.PROPERTY_GROUP_ID = #{propertyGroupId}
) WHERE RN BETWEEN #{offset} + 1 AND #{offset} + #{limit} ORDER BY RN

SELECT COUNT(*)
FROM FWK_WAS_PROPERTY
WHERE INSTANCE_ID = #{instanceId}

    AND PROPERTY_GROUP_ID = #{propertyGroupId}
